    if "CSCW" in text:
        indicators.append("CSCW")
    if "DIS " in text:
        indicators.append("DIS")

    results.append({
        "title": title,
        "count": count,
        "indicators": indicators
    })

print("__RESULT__:")
print(json.dumps(results))

