import json
import os
import re

citations_var = locals()['var_function-call-2106421940036629061']
papers_var = locals()['var_function-call-1144050169456898766']

if isinstance(citations_var, str) and os.path.exists(citations_var):
    with open(citations_var, 'r') as f:
        citations_data = json.load(f)
else:
    citations_data = citations_var

if isinstance(papers_var, str) and os.path.exists(papers_var):
    with open(papers_var, 'r') as f:
        papers_list = json.load(f)
else:
    papers_list = papers_var

matched_papers = []

# Regex: CHI followed by year, or full name, or CHI Conference
pattern = re.compile(r"(Conference on Human Factors in Computing Systems)|(\bCHI\s+20\d{2})|(\bCHI\s+'\d{2})|(\bCHI\s+Conference)", re.IGNORECASE)

for p in papers_list:
    text = p.get('text', '')
    header = text[:1000].upper() # Check first 1000 chars for venue

    # Check regex in FULL text
    match = pattern.search(text)

    is_chi = False
    if match:
        is_chi = True

        # Check exclusions in header
        if "UBICOMP" in header:
            is_chi = False
        if "DIS " in header or "DIS '" in header:
            is_chi = False
        if "CSCW" in header:
            is_chi = False
        if "TEI " in header:
            is_chi = False
        if "IUI " in header:
            is_chi = False

    if is_chi:
        title = p['filename'][:-4] if p['filename'].endswith('.txt') else p['filename']
        citation_count = 0
        for r in citations_data:
            if r['title'] == title:
                citation_count = int(r['citation_count'])
                break

        matched_papers.append({
            "title": title,
            "citations": citation_count
        })

total = sum([m['citations'] for m in matched_papers])
print(f"Total Citations: {total}")
# print("Matches:", json.dumps(matched_papers))

print("__RESULT__:")
print(json.dumps(total))

